import{_ as r,o as e,c as l,ai as t,aj as a,ak as i,al as d,am as s,an as c,ao as n,ap as b,aq as g,ar as h}from"./chunks/framework.DSAV_C12.js";const P=JSON.parse('{"title":"mzkbot 使用帮助","description":"","frontmatter":{},"headers":[],"relativePath":"help.md","filePath":"help.md"}'),p={name:"help.md"};function k(m,o,u,_,f,x){return e(),l("div",null,[...o[0]||(o[0]=[t('<h1 id="mzkbot-使用帮助" tabindex="-1">mzkbot 使用帮助 <a class="header-anchor" href="#mzkbot-使用帮助" aria-label="Permalink to “mzkbot 使用帮助”">​</a></h1><h2 id="对话" tabindex="-1">对话 <a class="header-anchor" href="#对话" aria-label="Permalink to “对话”">​</a></h2><ul><li><code>@mzkbot</code> 后接内容即可进行对话（例如：<code>@mzkbot 你好</code>）</li></ul><p>目前的主人格为<code>晓山瑞希</code>，以后将会开放切换人格功能</p><blockquote><p>该功能在使用高峰期时可能会出现延迟现象</p></blockquote><img src="'+a+'" alt="描述文字" width="60%"><h2 id="签到" tabindex="-1">签到 <a class="header-anchor" href="#签到" aria-label="Permalink to “签到”">​</a></h2><ul><li><code>@mzkbot 签到</code>或<code>签到</code></li></ul><blockquote><p>该功能在使用高峰期时可能会出现延迟现象</p></blockquote><img src="'+i+'" alt="描述文字" width="60%"><h2 id="世界计划猜歌" tabindex="-1">世界计划猜歌 <a class="header-anchor" href="#世界计划猜歌" aria-label="Permalink to “世界计划猜歌”">​</a></h2><ul><li><code>@mzkbot pjsk猜歌</code>（普通猜歌）</li><li><code>@mzkbot pjsk猜歌1</code>（2倍速猜歌）</li></ul><img src="'+d+'" alt="描述文字" width="50%"><img src="'+s+'" alt="描述文字" width="50%"><h2 id="网易云点歌" tabindex="-1">网易云点歌 <a class="header-anchor" href="#网易云点歌" aria-label="Permalink to “网易云点歌”">​</a></h2><ul><li><code>@mzkbot 点歌 歌名</code></li></ul><img src="'+c+'" alt="描述文字" width="50%"><blockquote><p>你也可以通过自然语言进行点歌 <img src="'+n+'" alt="描述文字" width="60%"></p></blockquote><h2 id="赞我" tabindex="-1">赞我 <a class="header-anchor" href="#赞我" aria-label="Permalink to “赞我”">​</a></h2><ul><li><code>@mzkbot 赞我</code> 或 <code>赞我</code></li></ul><img src="'+b+'" alt="描述文字" width="60%"><h2 id="说话-即将弃用" tabindex="-1">说话（即将弃用） <a class="header-anchor" href="#说话-即将弃用" aria-label="Permalink to “说话（即将弃用）”">​</a></h2><ul><li>用法：<code>@mzkbot 说话 [内容]</code></li><li><strong>注意</strong>：仅支持中文，内容不可含空格或换行（否则截断至首个空格/换行处）。</li></ul><img src="'+g+'" alt="描述文字" width="60%"><h2 id="表情包生成" tabindex="-1">表情包生成 <a class="header-anchor" href="#表情包生成" aria-label="Permalink to “表情包生成”">​</a></h2><ul><li>生成表情包时无需 <code>@mzkbot</code>，直接发送关键词即可（如：<code>滚</code>、<code>亲</code>、<code>原神启动</code>）。</li><li><code>@mzkbot 表情列表</code> 获取关键词列表。</li></ul><img src="'+h+'" alt="描述文字" width="60%"><h2 id="sakurabot-相关功能" tabindex="-1">SakuraBOT 相关功能 <a class="header-anchor" href="#sakurabot-相关功能" aria-label="Permalink to “SakuraBOT 相关功能”">​</a></h2><blockquote><p>运行以下指令时，不需要 <code>@mzkbot</code></p></blockquote><h3 id="project-sekai-模块" tabindex="-1">Project Sekai 模块 <a class="header-anchor" href="#project-sekai-模块" aria-label="Permalink to “Project Sekai 模块”">​</a></h3><p>Project Sekai 是最早研发的模块，功能最丰富。<br><strong>用户数据操作</strong>：可添加 <code>tw/cn</code> 前缀触发国/台服专属功能。</p><h4 id="用户数据相关" tabindex="-1">用户数据相关 <a class="header-anchor" href="#用户数据相关" aria-label="Permalink to “用户数据相关”">​</a></h4><ul><li><strong>绑定</strong><br> 用法：<code>绑定 ID</code>（ID 可在游戏个人信息页查看）<br> 绑定后默认为「不给看」模式（无法被 <code>@</code>）。</li><li><strong>给看/不给看</strong>（全服通用）<br> 开放/关闭他人 <code>@</code> 你的权限。</li><li><strong>pjskprofile</strong><br> 获取个人信息（图片类似旧版 profile）。</li><li><strong>视奸</strong><br> 返回当前队伍综合力及构成。</li><li><strong>逮捕</strong><br> 查询 Expert Master FC/AP 进度（需上传数据）。</li></ul><blockquote><p><strong>重要</strong>：以下功能需上传数据方可使用，请先访问 <a href="http://go.mikuware.top/" target="_blank" rel="noreferrer">点我进入上传数据页面</a><br><strong>日服玩家</strong>：可直接复制引继信息给 Bot 实现上传（需重新引继一次）。</p></blockquote><h4 id="功能列表-需上传数据" tabindex="-1">功能列表（需上传数据） <a class="header-anchor" href="#功能列表-需上传数据" aria-label="Permalink to “功能列表（需上传数据）”">​</a></h4><ul><li><strong>rk</strong><br> 获取玩家排位信息。</li><li><strong>b39</strong><br> 获取 Rating 分数最高的 39 首歌曲及总分（仅供参考）。</li><li><strong>pjsk b30</strong><br> 获取 Rating 分数最高的 30 首歌曲及平均分（算法与 <code>b39</code> 不同，仅供参考）。</li><li><strong>pjsk进度(ex/apd)</strong><br> 查询 Master 歌曲完成情况（AP/FC/Clear/All）。<br> 支持 <code>pjsk进度ex</code>（Expert 难度）或 <code>pjsk进度apd</code>（Append 难度）。</li><li><strong>pjskdetail</strong><br> 获取个人详细信息（含金币、水晶、家具练度、每日挑战进度等，介意可私聊查询）。</li><li><strong>pjskcard</strong><br> 获取个人卡牌图鉴（支持 <code>pjskcard+角色花名</code> 查看单角色图鉴）。</li><li><strong>pjskevent</strong><br> 获取个人 10 次最高排名的活动记录（仅当期获取排名奖励时记录）。</li></ul><h4 id="卡组推荐" tabindex="-1">卡组推荐 <a class="header-anchor" href="#卡组推荐" aria-label="Permalink to “卡组推荐”">​</a></h4><ul><li><strong>组卡</strong><br> 返回指定箱活中最佳卡组 Top 7（按活动点数排序）。<br> 用法：<code>组卡 [队名] [属性]</code><br> 队名：<code>ln/mmj/vbs/ws/25/vs</code>；属性：<code>绿/粉/橙/蓝/紫</code><br> 示例：<code>组卡 ln 橙</code></li><li><strong>活动组卡</strong><br> 返回当前活动最佳卡组 Top 7。<br> 用法：<code>活动组卡 [歌曲名] [难度]</code><br> 默认难度：Expert；默认歌曲：<code>独りんぼエンヴィー</code><br> 示例：<code>活动组卡 龙 hard</code>（WL 活动时，首参数识别为角色名）。</li><li><strong>挑战组卡</strong><br> 返回每日挑战最佳卡组 Top 7。<br> 用法：<code>挑战组卡 [角色名] [歌曲名] [难度]</code><br> 默认难度：Expert；默认歌曲：<code>独りんぼエンヴィー</code><br> 示例：<code>挑战组卡 ick 10th master</code></li><li><strong>最强组卡</strong><br> 返回同色同队中分数最高的卡组 Top 7。<br> 用法：<code>最强组卡</code>（默认歌曲：Expert 难度 <code>独りんぼエンヴィー</code>，无需参数）。</li></ul><h4 id="其他功能-无需上传数据" tabindex="-1">其他功能（无需上传数据） <a class="header-anchor" href="#其他功能-无需上传数据" aria-label="Permalink to “其他功能（无需上传数据）”">​</a></h4><ul><li><strong>id</strong><br> 返回当前 QQ 号绑定的 ID。</li><li><strong>sk</strong><br> 查询活动排名或指定档线（WL 活动时可加角色花名查单榜）。</li><li><strong>分数线/sk线</strong><br> 获取当前档线分数（数据延迟 ≤5 分钟，WL 活动可加角色名查单榜）。</li><li><strong>ss</strong><br> 获取当前档线时速（计算方式：20 分钟速度 × 3）。</li><li><strong>wlss</strong><br> 获取当前角色单榜档线时速（日服限定，计算方式同 <code>ss</code>）。</li><li><strong>查房</strong><br> 获取本人/目标档线最近 1 小时活动情况（无法确认烤森刷周回，请自行判断）。</li><li><strong>pinfo</strong><br> 查询歌曲信息（支持名称/花名），可用 <code>pset 新昵称 to 旧昵称</code> 设置花名，<code>pdel 昵称</code> 删除。</li><li><strong>charinfo</strong><br> 查询角色所有花名（支持名称/花名），可用 <code>charset</code>/<code>chardel</code> 修改。</li><li><strong>难度排行</strong><br> 用法：<code>难度排行 [level] [难度]</code>（如 <code>难度排行 10 紫</code>）<br> 支持 <code>fc/ap</code> 前缀查看 FC/AP 难度排行（定数仅支持紫谱及早期红谱）。</li><li><strong>谱面预览</strong><br> 用法：<code>[歌曲名] (谱/铺)面预览</code>（默认 Master 难度）<br> 可用 <code>[歌曲名]ex(谱/铺)面预览</code> 查 Expert 难度，<code>[歌曲名]apd(谱/铺)面预览</code> 查 Append 难度。</li><li><strong>技能预览</strong><br> 用法：<code>[歌曲名]技能预览</code>（默认 Master 难度）<br> 可用 <code>[歌曲名]ex/apd技能预览</code> 查 Expert/Append 难度。</li><li><strong>findcard/查卡</strong><br> 返回满足条件的卡牌（最多 3 个参数）： <ul><li>1 参数：队名/队名+vs/角色名</li><li>2 参数：稀有度（<code>4/3/2/1/birthday/限定</code>）或属性（<code>绿/粉/橙/蓝/紫</code>）</li><li>3 参数：稀有度+属性 或 属性+稀有度。</li></ul></li><li><strong>card</strong><br> 用法：<code>card [卡编号]</code>，返回卡面图片。</li><li><strong>cardinfo</strong><br> 用法：<code>cardinfo [卡编号]</code>，返回卡面基础信息（属性、技能、当期活动等）。</li><li><strong>5v5 胜率</strong><br> 返回 5v5 活动双方队伍胜率（每小时更新）。</li><li><strong>5v5 分数</strong><br> 活动结算时获取双方分数（疑似仅支持首次结算）。</li><li><strong>tf启动</strong><br> 5v5 活动中，为绑定 ID 用户赠送 3 次无偿火（功能待恢复）。</li><li><strong>pjsk听歌识曲</strong><br> 直接触发：随机剪取 4-7 秒音源，40 秒内回答歌曲名/花名。<br> 用法：<code>结束猜曲</code> 中断。</li><li><strong>pjsk猜卡面</strong><br> 直接触发：随机截取 3/4 星卡面（250×250 像素），40 秒内回答角色名/花名。<br> 用法：<code>结束猜卡面</code> 中断。</li><li><strong>pjsk抽卡</strong><br> 用法：<code>pjsk抽卡</code>（默认 10 连，图片返回）<br><code>pjskXX连</code>（XX 连，文字返回）<br><code>pjsk反抽卡</code>（反转 2/4 星概率，需指定卡池编号）。</li><li><strong>pjsk表情制作</strong><br> 用法：<code>pjsk -h</code> 查看详细说明。</li><li><strong>看</strong><br> 用法：<code>看 [角色名]</code>，返回随机卡图。</li><li><strong>随个</strong><br> 用法：<code>随个 [组合名] [level]</code>，返回随机指定 Level 歌曲信息。</li><li><strong>葱什么</strong><br> 返回随机歌曲信息。</li><li><strong>活动</strong><br> 查看当前活动信息（加活动编号可查指定活动，如 <code>活动86</code>）。</li><li><strong>findevent</strong><br> 查询满足条件的活动信息（用法：<code>findevent help</code>）。</li><li><strong>查bpm</strong><br> 查询指定 BPM 或包含指定 BPM 的歌曲。</li><li><strong>查物量</strong><br> 查询谱面物量等于指定值的歌曲及难度。</li></ul><blockquote><p><strong>额外说明</strong>：每日 10:00 自动检测更新并推送至订阅群聊，同时推送结活 Live 通知。</p></blockquote>',41)])])}const v=r(p,[["render",k]]);export{P as __pageData,v as default};
